styles.globalCss:
.hp-svg-block {
  background: rgb(255, 255, 255);
  border: 1px solid rgb(215, 226, 237);
  border-radius: 18px;
  box-shadow: 0 10px 22px rgba(16, 36, 66, 0.06);
  overflow: hidden;
}
.hp-svg-heading {
  padding: 14px 18px 2px;
  color: rgb(16, 36, 66);
  font-size: 15px;
  font-weight: 760;
}
.hp-svg-interactive {
  cursor: pointer;
}
.hp-svg-interactive:focus {
  outline: 3px solid rgba(37, 99, 235, 0.28);
  outline-offset: 3px;
}
